// append to tests/scoring.test.ts

import { roundToTwo } from '@/app/services/scoring'

describe('roundToTwo', () => {
  it('rounds down at the third decimal', () => {
    expect(roundToTwo(10.334)).toBe(10.33)
  })

  it('rounds up at the third decimal', () => {
    expect(roundToTwo(10.335)).toBe(10.34)
  })

  it('leaves integers unchanged', () => {
    expect(roundToTwo(5)).toBe(5)
  })

  it('handles zero', () => {
    expect(roundToTwo(0)).toBe(0)
  })
})

describe('buildWeightedModeStats — edge cases', () => {
  it('sets accuracyPercentage to 0 when the first ever score is multiplayer', () => {
    const stats = buildWeightedModeStats(null, 'multiplayer', 80)
    // no prior singleplayer → singleplayer.averageScore is 0
    expect(stats.accuracyPercentage).toBe(0)
    expect(stats.multiplayer.matchCount).toBe(1)
  })

  it('rounds a fractional score in lastScore and totalScore', () => {
    const stats = buildWeightedModeStats(null, 'singleplayer', 33.333)
    expect(stats.lastScore).toBe(33.33)
    expect(stats.singleplayer.totalScore).toBe(33.33)
  })

  it('recovers gracefully from malformed existingStats with non-numeric matchCount', () => {
    const malformed = { singleplayer: { matchCount: 'bad' as unknown as number, totalScore: 0, averageScore: 0 } }
    const stats = buildWeightedModeStats(malformed, 'singleplayer', 50)
    // matchCount coerced to 0, then +1 = 1
    expect(stats.singleplayer.matchCount).toBe(1)
    expect(stats.singleplayer.averageScore).toBe(50)
  })
})

describe('computeCompositeScore — edge cases', () => {
  it('returns 0 for a user with no games and no matches', () => {
    expect(computeCompositeScore({ avgNormalizedScore: 0, gamesPlayed: 0, totalMatchCount: 0 })).toBe(0)
  })

  it('hits the diversity cap exactly at 5 games', () => {
    // 5 games * 4 = 20 (cap); 0 skill; 1 match → sqrt(1)*2 = 2 → total 22
    expect(computeCompositeScore({ avgNormalizedScore: 0, gamesPlayed: 5, totalMatchCount: 1 })).toBe(22)
  })

  it('hits the experience cap exactly at 25 matches', () => {
    // sqrt(25)*2 = 10 (cap); 0 skill; 0 games → total 10
    expect(computeCompositeScore({ avgNormalizedScore: 0, gamesPlayed: 0, totalMatchCount: 25 })).toBe(10)
  })
})

describe('aggregateGlobalLeaderboard — edge cases', () => {
  it('includes a user with stats but no scores (gamesPlayed 0, avgNormalized 0)', () => {
    const scores: ScoreRow[] = []
    const stats: StatsRow[] = [{ uid: 'ghost', gameId: 'chess', totalMatchCount: 5 }]

    const result = aggregateGlobalLeaderboard(scores, stats)

    expect(result).toHaveLength(1)
    expect(result[0].uid).toBe('ghost')
    expect(result[0].gamesPlayed).toBe(0)
    expect(result[0].avgNormalizedScore).toBe(0)
  })

  it('excludes a user with scores but no stats (stats drive the result)', () => {
    const scores: ScoreRow[] = [{ uid: 'phantom', gameId: 'chess', bestScore: 100 }]
    const stats: StatsRow[] = []

    const result = aggregateGlobalLeaderboard(scores, stats)

    expect(result).toHaveLength(0)
  })

  it('uses last-seen score when a user has duplicate rows for the same game', () => {
    const scores: ScoreRow[] = [
      { uid: 'alice', gameId: 'chess', bestScore: 90 },
      { uid: 'alice', gameId: 'chess', bestScore: 10 }, // overwrites 90
    ]
    const stats: StatsRow[] = [{ uid: 'alice', gameId: 'chess', totalMatchCount: 2 }]

    const result = aggregateGlobalLeaderboard(scores, stats)
    // max for chess is 90 (first row sets it), alice's score is 10 → normalized = 10/90 * 100 ≈ 11.1
    expect(result[0].avgNormalizedScore).toBeLessThan(100)
  })
})

describe('aggregateGameLeaderboard — edge cases', () => {
  it('returns empty array for empty input', () => {
    expect(aggregateGameLeaderboard([], 'chess')).toEqual([])
  })

  it('returns empty array when no rows match the requested gameId', () => {
    const rows: ScoreRow[] = [{ uid: 'a', gameId: '2048', bestScore: 50 }]
    expect(aggregateGameLeaderboard(rows, 'chess')).toEqual([])
  })

  it('includes all rows for the same uid (no dedup)', () => {
    const rows: ScoreRow[] = [
      { uid: 'a', gameId: 'chess', bestScore: 80 },
      { uid: 'a', gameId: 'chess', bestScore: 40 }, // same user, two entries
    ]
    const result = aggregateGameLeaderboard(rows, 'chess')
    expect(result).toHaveLength(2)
    expect(result.map((r) => r.bestScore)).toEqual([80, 40])
  })
})

describe('aggregateGamePopularity — edge cases', () => {
  it('returns empty object for empty input', () => {
    expect(aggregateGamePopularity([])).toEqual({})
  })

  it('coerces non-numeric totalMatchCount to 0', () => {
    const stats = [{ uid: 'a', gameId: 'chess', totalMatchCount: NaN }]
    expect(aggregateGamePopularity(stats)).toEqual({ chess: 0 })
  })
})
